def catalanHankelMatrix (k : ℕ) : Matrix (Fin k) (Fin k) ℤ :=
  Matrix.of fun i j => (catalan ((i : ℕ) + (j : ℕ)) : ℤ)

/-- The Catalan Hankel matrix is symmetric (since c_{i+j} = c_{j+i}). -/

def xDecreasing {k : ℕ} (A : kVertex (ℤ × ℤ) k) : Prop :=
  ∀ i j : Fin k, i ≤ j → xCoord (A j) ≤ xCoord (A i)

/-- A k-vertex has weakly increasing y-coordinates -/

def yIncreasing {k : ℕ} (A : kVertex (ℤ × ℤ) k) : Prop :=
  ∀ i j : Fin k, i ≤ j → yCoord (A i) ≤ yCoord (A j)

/-- Discrete intermediate value theorem for integers (auxiliary version with explicit n) -/

def catalan (n : ℕ) : ℕ := (2 * n).choose n / (n + 1)

/-- Our explicit definition of `catalan` equals Mathlib's recursive `catalan`.

This follows from `catalan_eq_centralBinom_div` in Mathlib. -/

def IsPathFinite (D : SimpleDigraph V) : Prop :=
  ∀ u v : V, Set.Finite {p : Path D | p.start = u ∧ p.finish = v}

/-- A digraph is acyclic if it has no directed cycles.
    Convention conv.lgv.digraph(c) -/

def LatticePath.vertices (path : LatticePath) (start : LatticePoint) : List LatticePoint :=
  start :: path.scanl (fun p s => s.apply p) start |>.tail

/-- Check if a path goes from point a to point b. -/

def Path.start {D : SimpleDigraph V} (p : Path D) : V :=
  p.vertices.head p.nonempty

/-- The ending vertex of a path -/

def inversions (σ : Perm (Fin n)) : Finset (Fin n × Fin n) :=
  Finset.filter (fun p => p.1 < p.2 ∧ σ p.2 < σ p.1) (Finset.univ)

/-- The length of a permutation is the number of its inversions. -/

def verticalStripUpperBound (mu : NPartition N) (i : Fin N) : ℕ :=
  mu.parts i + 1

/-- A function from Fin N to ℕ that could potentially form a vertical n-strip with μ. -/

def Filling {N : ℕ} [NeZero N] (lam : NPartition N) : Type :=
  { c // c ∈ lam.youngDiagram } → Fin N

/-- Fillings are finite. -/

def isSSYTFillingNonSkew (lam : NPartition N) (f : Filling lam) : Prop :=
  isRowWeakFilling lam f ∧ isColStrictFilling lam f

